import { useState } from 'react';
import { Link } from 'react-router-dom';
import { usePortfolio } from '../contexts/PortfolioContext';
import { RiskBadge, ReturnDisplay, CategoryBadge, LiquidityBadge, HorizonBadge } from './Badges';
import { formatPKR } from '../utils/finance';
import './ProductCard.css';

export default function ProductCard({ product, onAddToPortfolio }) {
  const { isInPortfolio, addToPortfolio, removeFromPortfolio } = usePortfolio();
  const inPortfolio = isInPortfolio(product.id);
  const [justAdded, setJustAdded] = useState(false);

  function handlePortfolioClick(e) {
    e.preventDefault();
    if (inPortfolio) {
      removeFromPortfolio(product.id);
    } else {
      addToPortfolio(product);
      setJustAdded(true);
      setTimeout(() => setJustAdded(false), 2000);
    }
    if (onAddToPortfolio) onAddToPortfolio(product);
  }

  return (
    <div className="product-card card">
      {/* Static visible info */}
      <div className="pc-top">
        <div className="pc-header">
          <CategoryBadge category={product.category} />
          <RiskBadge riskLevel={product.riskLevel} />
        </div>
        <h3 className="pc-name">{product.name}</h3>
        <div className="pc-return">
          <ReturnDisplay value={product.expectedReturn} />
          <span className="pc-return-label">Expected Annual Return</span>
        </div>
      </div>

      {/* Hover overlay with more details */}
      <div className="details-overlay">
        <div className="pc-details">
          <div className="pc-detail-row">
            <LiquidityBadge liquidity={product.liquidity} />
            <HorizonBadge timeHorizon={product.timeHorizon} />
          </div>
          <div className="pc-min-invest">
            <span className="pc-detail-label">Min. Investment</span>
            <span className="pc-detail-val">{formatPKR(product.minInvestment)}</span>
          </div>
        </div>
      </div>

      {/* Actions */}
      <div className="pc-actions">
        <Link to={`/product/${product.id}`} className="btn btn-outline btn-sm">
          View Details
        </Link>
        <button
          className={`btn btn-sm pc-portfolio-btn ${inPortfolio ? 'in-portfolio' : ''} ${justAdded ? 'just-added' : ''}`}
          onClick={handlePortfolioClick}
        >
          {justAdded ? '✓ Added' : inPortfolio ? '✓ In Portfolio' : '+ Portfolio'}
        </button>
      </div>
    </div>
  );
}
